import { useMemo, useState } from "react";

type Status = "operating" | "planned" | "under_construction" | "approved" | "unknown";
type Lifecycle = "raw_import" | "local_working" | "reviewed" | "promoted_public" | "rejected_duplicate" | "retired";
type Precision = "public_dataset" | "city_level" | "county_level" | "state_level" | "unknown";
type Confidence = "high" | "medium" | "low";
type SourceType = "public_dataset" | "permit" | "utility" | "operator" | "news" | "review" | "other";
type QualityBand = "strong" | "moderate" | "weak" | "blocked";
type RegionMode = "state" | "county";
type TaskStatus = "open" | "in_progress" | "blocked" | "done" | "dismissed";
type TaskCategory = "needs_second_source" | "needs_public_url" | "needs_permit_receipt" | "needs_utility_receipt" | "needs_location_review" | "needs_confidence_review" | "needs_warning_resolution" | "needs_source_quality" | "ready_for_promotion" | "manual_follow_up";
type BriefScope = "record" | "region";
type ChecklistStatus = "pass" | "warning" | "fail" | "needs_human";
type AuditEventType = "import" | "receipt" | "task" | "brief" | "reviewed" | "promotion" | "session_restore" | "note" | "quality" | "change" | "approval";
type ApprovalStatus = "pending" | "approved" | "rejected";

type Receipt = { receiptId?: string; sourceName: string; sourceType: SourceType; sourceUrl?: string; retrievedAt: string; claim: string; confidence: Confidence; batchId?: string };
type LedgerRecord = { id: string; name: string; operator: string; status: Status; state: string; county: string; city?: string; precision: Precision; capacityMW?: number; lifecycle: Lifecycle; confidenceScore: number; reviewWarnings: string[]; receipts: Receipt[]; notes: string[]; importBatchId?: string };
type ImportWarning = { rowNumber: number; level: "info" | "warning" | "blocking"; field?: string; message: string };
type ImportPreview = { batchId: string; createdAt: string; origin: string; rows: Array<{ rowNumber: number; record: LedgerRecord; warnings: ImportWarning[] }>; warnings: ImportWarning[]; digest: string };
type ImportHistoryItem = { batchId: string; committedAt: string; origin: string; rowsCommitted: number; warningCount: number; digest: string };
type ReceiptDraft = { sourceName: string; sourceType: SourceType; sourceUrl: string; retrievedAt: string; claim: string; confidence: Confidence };
type ReceiptEditHistoryItem = { receiptId: string; recordId: string; recordName: string; addedAt: string; sourceName: string; sourceType: SourceType; confidence: Confidence; resolvedWarnings: string[]; remainingWarnings: number; digest: string };
type SourceQualityReport = { recordId: string; score: number; band: QualityBand; receiptCount: number; sourceTypeCount: number; publicLinkCoverage: number; newestReceiptDaysOld: number | null; highImpactClaimCoverage: "not_applicable" | "needs_second_source" | "covered"; strengths: string[]; gaps: string[]; digest: string };
type RegionalSummary = { id: string; mode: RegionMode; label: string; state: string; county?: string; records: number; canonical: number; needsReview: number; receipts: number; averageQuality: number; qualityBands: Record<QualityBand, number>; reviewGaps: string[]; digest: string };
type ReviewTask = { id: string; recordId: string; regionId?: string; title: string; category: TaskCategory; status: TaskStatus; priority: "low" | "medium" | "high"; detail: string; createdAt: string; source: "generated" | "manual" };
type CanonicalChecklistItem = { id: string; label: string; status: ChecklistStatus; detail: string };
type PromotionReceipt = { promotionId: string; recordId: string; recordName: string; promotedAt: string; reviewer: string; reason: string; checklist: CanonicalChecklistItem[]; sourceQuality: SourceQualityReport; publicBriefReady: boolean; safetyAcknowledged: boolean; priorLifecycle: Lifecycle; digest: string };
type SessionHistoryItem = { sessionId: string; sessionName: string; restoredAt: string; source: string; recordsRestored: number; digest: string };
type AuditTimelineEvent = { id: string; type: AuditEventType; recordId: string; title: string; occurredAt: string; actor?: string; detail: string; status?: string; digest: string };
type PromotionAuditTimeline = { schema: string; generatedAt: string; appVersion: string; recordId: string; recordName: string; events: AuditTimelineEvent[]; summary: { imports: number; receipts: number; tasks: number; briefs: number; promotions: number; changes: number; approvals: number; sessionRestores: number; latestEvent: string | null }; digest: string };
type PublicBrief = { schema: string; generatedAt: string; appVersion: string; scope: BriefScope; title: string; summary: string; reviewOnlyNotice: string; boundary: string[]; keyClaims: string[]; sourceReceipts: Array<{ sourceName: string; sourceType: SourceType; sourceUrl?: string; claim: string; confidence: Confidence; retrievedAt: string }>; unresolvedGaps: string[]; quality: SourceQualityReport | { averageQuality: number; qualityBands: Record<QualityBand, number>; regionalRecords: number }; relatedRecords: Array<{ id: string; name: string; state: string; county: string; canonicalBlockers: string[] }>; digest: string };
type RecordChangeDraft = { name: string; operator: string; status: Status; lifecycle: Lifecycle; state: string; county: string; city: string; precision: Precision; capacityMW: string; confidenceScore: string; reviewWarnings: string };
type ChangeDelta = { field: keyof RecordChangeDraft; before: string; after: string; impact: "low" | "medium" | "high" };
type ChangeReceipt = { changeId: string; recordId: string; recordName: string; changedAt: string; reviewer: string; reason: string; deltas: ChangeDelta[]; beforeQuality: SourceQualityReport; afterQuality: SourceQualityReport; canonicalBefore: string[]; canonicalAfter: string[]; digest: string };
type ChangeApprovalRequest = { approvalId: string; recordId: string; recordName: string; requestedAt: string; requestedBy: string; reason: string; status: ApprovalStatus; deltas: ChangeDelta[]; recordBefore: LedgerRecord; recordAfter: LedgerRecord; beforeQuality: SourceQualityReport; afterQuality: SourceQualityReport; canonicalBefore: string[]; canonicalAfter: string[]; decisionReviewer?: string; decisionNote?: string; decidedAt?: string; appliedChangeId?: string; digest: string };
type LocalReviewSession = { schema: string; generatedAt: string; appVersion: string; sessionName: string; records: LedgerRecord[]; importHistory: ImportHistoryItem[]; receiptHistory: ReceiptEditHistoryItem[]; promotionHistory: PromotionReceipt[]; changeHistory: ChangeReceipt[]; approvalQueue: ChangeApprovalRequest[]; sessionHistory: SessionHistoryItem[]; taskStatusOverrides: Record<string, TaskStatus>; manualTasks: ReviewTask[]; uiState: { selectedId: string; query: string; stateFilter: string; mode: "all" | "canonical" | "review"; regionMode: RegionMode; selectedRegionId: string; briefScope: BriefScope }; digest: string };

const APP_VERSION = "2.3.0";
const validStatuses: Status[] = ["operating", "planned", "under_construction", "approved", "unknown"];
const validSourceTypes: SourceType[] = ["public_dataset", "permit", "utility", "operator", "news", "review", "other"];
const validPrecisions: Precision[] = ["public_dataset", "city_level", "county_level", "state_level", "unknown"];
const publicBoundary = ["Public-data only", "No hidden network calls", "No private facility discovery", "No security-sensitive enrichment", "City/county precision unless exact location is already public"];
const reviewOnlyNotice = "This brief is a public-data review aid. It is not proof of truth, not a complete national registry, not a targeting map, and not a substitute for human review of the cited sources.";
const sampleCsv = `id,name,operator,status,state,county,city,capacity_mw,confidence,source,source_type,source_url,source_claim,retrieved_at\ndcl-public-review-001,Sample Public Atlas Candidate,Unknown,operating,VA,Loudoun County,Ashburn,0,72,Example public dataset,public_dataset,https://example.org/public-dataset,"Public dataset row for review workflow testing.",2026-06-13\ndcl-public-review-002,Sample Permit Review Candidate,Unknown,approved,IA,Polk County,Des Moines,120,66,Example county permit,permit,https://example.org/permit,"Permit mentions a proposed facility; MW claim needs a second source.",2026-06-13`;
const starterRecords: LedgerRecord[] = [
  { id: "dcl-demo-ashburn-va", name: "Northern Virginia Public Atlas Cluster", operator: "Multiple / unknown", status: "operating", state: "VA", county: "Loudoun County", city: "Ashburn", precision: "city_level", capacityMW: 0, lifecycle: "local_working", confidenceScore: 72, reviewWarnings: ["Demo record; replace with public-source imports before promotion."], receipts: [{ sourceName: "Demo seed", sourceType: "review", retrievedAt: "2026-06-13T00:00:00.000Z", claim: "City-level demo row for UI testing only.", confidence: "low" }], notes: [] },
  { id: "dcl-demo-phoenix-az", name: "Phoenix Public Review Candidate", operator: "Unknown", status: "planned", state: "AZ", county: "Maricopa County", city: "Phoenix", precision: "county_level", capacityMW: 0, lifecycle: "raw_import", confidenceScore: 61, reviewWarnings: ["Needs a second public source.", "Needs public URL."], receipts: [{ sourceName: "Demo seed", sourceType: "review", retrievedAt: "2026-06-13T00:00:00.000Z", claim: "County-level placeholder for workflow testing.", confidence: "low" }], notes: [] },
  { id: "dcl-demo-des-moines-ia", name: "Midwest Utility Filing Candidate", operator: "Unknown", status: "approved", state: "IA", county: "Polk County", city: "Des Moines", precision: "county_level", lifecycle: "raw_import", confidenceScore: 54, reviewWarnings: ["Needs permit source.", "Needs utility source."], receipts: [{ sourceName: "Demo seed", sourceType: "review", retrievedAt: "2026-06-13T00:00:00.000Z", claim: "Demonstrates a low-confidence review queue item.", confidence: "low" }], notes: [] }
];

const nowIso = () => new Date().toISOString();
const todayInputDate = () => new Date().toISOString().slice(0, 10);
function digest(payload: unknown) { const text = JSON.stringify(payload); let hash = 2166136261; for (let i = 0; i < text.length; i += 1) { hash ^= text.charCodeAt(i); hash += (hash << 1) + (hash << 4) + (hash << 7) + (hash << 8) + (hash << 24); } return `dcl-${(hash >>> 0).toString(16).padStart(8, "0")}`; }
function safeIso(value: string | undefined, fallback = nowIso()) { if (!value) return fallback; const parsed = new Date(value); return parsed.toString() === "Invalid Date" ? fallback : parsed.toISOString(); }
function daysOld(dateText: string) { const parsed = new Date(dateText); if (parsed.toString() === "Invalid Date") return null; return Math.max(0, Math.round((Date.now() - parsed.getTime()) / 86_400_000)); }
function confidenceLabel(score: number): Confidence { if (score >= 80) return "high"; if (score >= 55) return "medium"; return "low"; }
function qualityBand(score: number): QualityBand { if (score >= 80) return "strong"; if (score >= 65) return "moderate"; if (score >= 45) return "weak"; return "blocked"; }
function clampScore(value: string | number) { return Math.max(0, Math.min(100, Number(value) || 0)); }
function parseNumber(value: string) { const parsed = Number(value); return Number.isFinite(parsed) && parsed > 0 ? parsed : undefined; }

function scoreRecord(record: LedgerRecord): SourceQualityReport {
  const receiptCount = record.receipts.length;
  const sourceTypeCount = new Set(record.receipts.map((receipt) => receipt.sourceType)).size;
  const publicLinks = record.receipts.filter((receipt) => Boolean(receipt.sourceUrl)).length;
  const publicLinkCoverage = receiptCount ? Math.round((publicLinks / receiptCount) * 100) : 0;
  const receiptAges = record.receipts.map((receipt) => daysOld(receipt.retrievedAt)).filter((age): age is number => age !== null);
  const newestReceiptDaysOld = receiptAges.length ? Math.min(...receiptAges) : null;
  const highImpactClaimCoverage = record.capacityMW && record.capacityMW > 0 ? receiptCount >= 2 && publicLinks >= 1 ? "covered" : "needs_second_source" : "not_applicable";
  let score = 15;
  const strengths: string[] = [];
  const gaps: string[] = [];
  if (receiptCount >= 2) { score += 20; strengths.push("two or more receipts"); } else gaps.push("needs at least two receipts");
  if (sourceTypeCount >= 2) { score += 15; strengths.push("source diversity"); } else gaps.push("needs source diversity");
  if (publicLinkCoverage >= 80) { score += 15; strengths.push("strong public-link coverage"); } else gaps.push("needs stronger public-link coverage");
  if (newestReceiptDaysOld !== null && newestReceiptDaysOld <= 365) { score += 10; strengths.push("recent receipt present"); } else gaps.push("needs recent receipt review");
  if (highImpactClaimCoverage === "covered" || highImpactClaimCoverage === "not_applicable") score += 10; else gaps.push("high-impact MW claim needs second source");
  if (record.confidenceScore >= 70) { score += 10; strengths.push("confidence at or above 70"); } else gaps.push("confidence below 70");
  if (record.reviewWarnings.length === 0) { score += 10; strengths.push("no unresolved review warnings"); } else gaps.push(`${record.reviewWarnings.length} unresolved review warning(s)`);
  if (record.precision === "unknown") { score -= 15; gaps.push("unknown location precision"); }
  const finalScore = Math.max(0, Math.min(100, score));
  return { recordId: record.id, score: finalScore, band: qualityBand(finalScore), receiptCount, sourceTypeCount, publicLinkCoverage, newestReceiptDaysOld, highImpactClaimCoverage, strengths, gaps, digest: digest({ recordId: record.id, finalScore, receiptCount, sourceTypeCount, publicLinkCoverage, newestReceiptDaysOld, highImpactClaimCoverage, gaps }) };
}
function canonicalBlockers(record: LedgerRecord, report = scoreRecord(record)) { const blockers: string[] = []; if (record.lifecycle !== "promoted_public") blockers.push("not promoted_public"); if (record.receipts.length === 0) blockers.push("missing receipt"); if (record.confidenceScore < 70) blockers.push("confidence below 70"); if (record.precision === "unknown") blockers.push("unknown location precision"); if (record.reviewWarnings.length > 0) blockers.push("review warnings remain"); if (report.score < 65) blockers.push("source quality below 65"); return blockers; }
function promotionChecklist(record: LedgerRecord, report: SourceQualityReport, publicBriefReady: boolean, safetyAcknowledged: boolean, reason: string): CanonicalChecklistItem[] { return [
  { id: "receipts", label: "Receipts attached", status: record.receipts.length > 0 ? "pass" : "fail", detail: `${record.receipts.length} receipt(s) attached.` },
  { id: "quality", label: "Source quality at or above 65", status: report.score >= 65 ? "pass" : "fail", detail: `Current source quality is ${report.score} (${report.band}).` },
  { id: "confidence", label: "Confidence at or above 70", status: record.confidenceScore >= 70 ? "pass" : "warning", detail: `Current confidence is ${record.confidenceScore}%.` },
  { id: "warnings", label: "No unresolved review warnings", status: record.reviewWarnings.length === 0 ? "pass" : "needs_human", detail: `${record.reviewWarnings.length} unresolved warning(s).` },
  { id: "precision", label: "Location precision is public-safe", status: record.precision !== "unknown" ? "pass" : "fail", detail: `Precision is ${record.precision}.` },
  { id: "brief", label: "Public brief reviewed", status: publicBriefReady ? "pass" : "needs_human", detail: publicBriefReady ? "Reviewer acknowledged public-brief readiness." : "Generate/review a public brief before promotion." },
  { id: "safety", label: "Safety boundary acknowledged", status: safetyAcknowledged ? "pass" : "fail", detail: safetyAcknowledged ? "Reviewer acknowledged public-data boundary." : "Reviewer must acknowledge safety boundary." },
  { id: "reason", label: "Reviewer reason provided", status: reason.trim().length >= 12 ? "pass" : "needs_human", detail: reason.trim().length >= 12 ? "Promotion reason captured." : "Promotion reason is required." }
]; }
function checklistPasses(items: CanonicalChecklistItem[]) { return items.every((item) => item.status === "pass" || item.status === "warning"); }

function splitCsvLine(line: string) { const values: string[] = []; let current = ""; let inQuotes = false; for (let index = 0; index < line.length; index += 1) { const char = line[index]; const next = line[index + 1]; if (char === "\"" && inQuotes && next === "\"") { current += "\""; index += 1; } else if (char === "\"") inQuotes = !inQuotes; else if (char === "," && !inQuotes) { values.push(current.trim()); current = ""; } else current += char; } values.push(current.trim()); return values; }
function parseCsvTable(text: string) { const lines = text.split(/\r?\n/).filter((line) => line.trim().length > 0); if (lines.length === 0) return { headers: [] as string[], rows: [] as { rowNumber: number; row: Record<string, string> }[] }; const headers = splitCsvLine(lines[0]).map((item) => item.trim().toLowerCase()); const rows = lines.slice(1).map((line, index) => { const values = splitCsvLine(line); const row: Record<string, string> = {}; headers.forEach((header, headerIndex) => { row[header] = values[headerIndex]?.trim() || ""; }); return { rowNumber: index + 2, row }; }); return { headers, rows }; }
function readCell(row: Record<string, string>, ...keys: string[]) { for (const key of keys) { const value = row[key]?.trim(); if (value) return value; } return ""; }
function pushWarning(warnings: ImportWarning[], rowNumber: number, level: ImportWarning["level"], message: string, field?: string) { warnings.push({ rowNumber, level, field, message }); }
function normalizeStatus(value: string): Status { const normalized = value.toLowerCase().trim().replace(/\s+/g, "_") as Status; return validStatuses.includes(normalized) ? normalized : "unknown"; }
function normalizeSourceType(value: string): SourceType { const normalized = value.toLowerCase().trim().replace(/\s+/g, "_") as SourceType; return validSourceTypes.includes(normalized) ? normalized : "other"; }
function normalizePrecision(row: Record<string, string>): Precision { const raw = readCell(row, "precision", "location_precision").toLowerCase().trim().replace(/\s+/g, "_") as Precision; if (raw && validPrecisions.includes(raw)) return raw; if (readCell(row, "city")) return "city_level"; if (readCell(row, "county")) return "county_level"; if (readCell(row, "state", "state_abb")) return "state_level"; return "unknown"; }
function buildImportPreview(text: string, origin: string, existingRecords: LedgerRecord[]): ImportPreview { const createdAt = nowIso(); const batchId = digest({ text, origin, createdAt }); const { headers, rows } = parseCsvTable(text); const warnings: ImportWarning[] = []; const existingIds = new Set(existingRecords.map((record) => record.id)); const previewIds = new Set<string>(); if (headers.length === 0) pushWarning(warnings, 1, "blocking", "CSV text is empty or missing a header row."); if (headers.length > 0 && rows.length === 0) pushWarning(warnings, 1, "blocking", "CSV has a header row but no data rows."); const previewRows = rows.map(({ rowNumber, row }) => { const rowWarnings: ImportWarning[] = []; const name = readCell(row, "name") || "Unnamed public record"; const state = readCell(row, "state", "state_abb") || "UNKNOWN"; const id = readCell(row, "id") || digest({ row, rowNumber, batchId }); const sourceUrl = readCell(row, "source_url", "url") || undefined; const confidenceScore = clampScore(readCell(row, "confidence", "confidence_score") || 50); const capacityMW = parseNumber(readCell(row, "capacity_mw", "power_mw", "mw")); if (existingIds.has(id)) pushWarning(rowWarnings, rowNumber, "blocking", `Record id "${id}" already exists in the workspace.`, "id"); if (previewIds.has(id)) pushWarning(rowWarnings, rowNumber, "blocking", `Record id "${id}" appears more than once in this import batch.`, "id"); previewIds.add(id); if (!readCell(row, "state", "state_abb")) pushWarning(rowWarnings, rowNumber, "blocking", "Missing state/state_abb.", "state"); if (!sourceUrl) pushWarning(rowWarnings, rowNumber, "info", "No source_url supplied; reviewers should preserve a public link outside the app.", "source_url"); if (capacityMW && capacityMW > 0) pushWarning(rowWarnings, rowNumber, "warning", "MW capacity is a high-impact claim and should have a second independent source before promotion.", "capacity_mw"); const record: LedgerRecord = { id, name, operator: readCell(row, "operator", "owner") || "Unknown", status: normalizeStatus(readCell(row, "status")), state, county: readCell(row, "county") || "Unknown county", city: readCell(row, "city") || undefined, precision: normalizePrecision(row), capacityMW, lifecycle: "raw_import", confidenceScore, reviewWarnings: ["Imported row needs human review before promotion.", ...rowWarnings.filter((warning) => warning.level !== "info").map((warning) => warning.message)], receipts: [{ sourceName: readCell(row, "source", "source_name") || "CSV import", sourceType: normalizeSourceType(readCell(row, "source_type")), sourceUrl, retrievedAt: safeIso(readCell(row, "retrieved_at", "retrieved") || createdAt), claim: readCell(row, "source_claim", "claim") || `Imported row for ${name}.`, confidence: confidenceLabel(confidenceScore), batchId }], notes: [`Imported through batch ${batchId} from ${origin}.`], importBatchId: batchId }; return { rowNumber, record, warnings: rowWarnings }; }); return { batchId, createdAt, origin, rows: previewRows, warnings, digest: digest({ batchId, previewRows, warnings }) }; }
function allPreviewWarnings(preview: ImportPreview | null) { return preview ? [...preview.warnings, ...preview.rows.flatMap((row) => row.warnings)] : []; }
function makeEmptyReceiptDraft(): ReceiptDraft { return { sourceName: "", sourceType: "public_dataset", sourceUrl: "", retrievedAt: todayInputDate(), claim: "", confidence: "medium" }; }
function isHttpUrl(value: string) { if (!value.trim()) return false; try { const url = new URL(value.trim()); return url.protocol === "http:" || url.protocol === "https:"; } catch { return false; } }
function validateReceiptDraft(draft: ReceiptDraft): ImportWarning[] { const warnings: ImportWarning[] = []; if (!draft.sourceName.trim()) pushWarning(warnings, 0, "blocking", "Source name is required.", "sourceName"); if (!draft.claim.trim()) pushWarning(warnings, 0, "blocking", "Claim text is required so reviewers know exactly what the source supports.", "claim"); if (!draft.retrievedAt.trim() || new Date(draft.retrievedAt).toString() === "Invalid Date") pushWarning(warnings, 0, "blocking", "Retrieved date must be a valid date.", "retrievedAt"); if (!draft.sourceUrl.trim()) pushWarning(warnings, 0, "warning", "No source URL supplied; public links make review and promotion stronger.", "sourceUrl"); if (draft.sourceUrl.trim() && !isHttpUrl(draft.sourceUrl)) pushWarning(warnings, 0, "blocking", "Source URL must start with http:// or https://.", "sourceUrl"); return warnings; }
function buildReceiptFromDraft(draft: ReceiptDraft, record: LedgerRecord, addedAt: string): Receipt { return { receiptId: digest({ recordId: record.id, draft, addedAt }), sourceName: draft.sourceName.trim(), sourceType: draft.sourceType, sourceUrl: draft.sourceUrl.trim() || undefined, retrievedAt: safeIso(draft.retrievedAt, addedAt), claim: draft.claim.trim(), confidence: draft.confidence }; }
function resolveWarningsAfterReceipt(record: LedgerRecord, receipt: Receipt) { const nextReceiptCount = record.receipts.length + 1; const hasPublicLink = Boolean(receipt.sourceUrl); const resolved: string[] = []; const remaining = record.reviewWarnings.filter((warning) => { const lower = warning.toLowerCase(); let shouldResolve = false; if (lower.includes("missing source") && receipt.sourceName) shouldResolve = true; if ((lower.includes("source_url") || lower.includes("source url") || lower.includes("public url")) && hasPublicLink) shouldResolve = true; if ((lower.includes("second public source") || lower.includes("second independent source") || lower.includes("needs a second public source")) && nextReceiptCount >= 2 && hasPublicLink) shouldResolve = true; if (lower.includes("needs permit source") && receipt.sourceType === "permit") shouldResolve = true; if (lower.includes("needs utility source") && receipt.sourceType === "utility") shouldResolve = true; if (lower.includes("imported row needs human review") && receipt.claim.length > 20) shouldResolve = true; if (shouldResolve) { resolved.push(warning); return false; } return true; }); const additions: string[] = []; if (!hasPublicLink) additions.push("Newest receipt has no source URL; attach a public link before promotion."); if (receipt.sourceType === "other") additions.push("Newest receipt source type is other; classify it before promotion if possible."); return { remaining: Array.from(new Set([...remaining, ...additions])), resolved }; }

function buildRegionalSummaries(records: LedgerRecord[], reports: SourceQualityReport[], mode: RegionMode): RegionalSummary[] { const reportMap = new Map(reports.map((report) => [report.recordId, report])); const groups = new Map<string, LedgerRecord[]>(); records.forEach((record) => { const key = mode === "state" ? record.state : `${record.state}::${record.county}`; groups.set(key, [...(groups.get(key) || []), record]); }); return Array.from(groups.entries()).map(([key, groupRecords]) => { const first = groupRecords[0]; const regionReports = groupRecords.map((record) => reportMap.get(record.id) || scoreRecord(record)); const qualityBandCounts: Record<QualityBand, number> = { strong: 0, moderate: 0, weak: 0, blocked: 0 }; regionReports.forEach((report) => { qualityBandCounts[report.band] += 1; }); const reviewGaps = Array.from(new Set([...regionReports.flatMap((report) => report.gaps), ...groupRecords.flatMap((record) => record.reviewWarnings)])).slice(0, 8); const canonical = groupRecords.filter((record) => canonicalBlockers(record, reportMap.get(record.id) || scoreRecord(record)).length === 0).length; const averageQuality = Math.round(regionReports.reduce((sum, report) => sum + report.score, 0) / Math.max(1, regionReports.length)); const label = mode === "state" ? first.state : `${first.county}, ${first.state}`; return { id: key, mode, label, state: first.state, county: mode === "county" ? first.county : undefined, records: groupRecords.length, canonical, needsReview: groupRecords.length - canonical, receipts: groupRecords.reduce((sum, record) => sum + record.receipts.length, 0), averageQuality, qualityBands: qualityBandCounts, reviewGaps, digest: digest({ key, mode, label, averageQuality, qualityBandCounts, reviewGaps }) }; }).sort((a, b) => b.records - a.records || a.label.localeCompare(b.label)); }
function recordsForRegion(region: RegionalSummary | undefined, records: LedgerRecord[]) { if (!region) return []; return records.filter((record) => region.mode === "state" ? record.state === region.state : record.state === region.state && record.county === region.county); }
function buildRegionalEvidencePacket(region: RegionalSummary, records: LedgerRecord[], reports: SourceQualityReport[]) { const regionRecords = recordsForRegion(region, records); const reportMap = new Map(reports.map((report) => [report.recordId, report])); const checklist = ["Map-safe summary only", "Review receipt coverage", "Resolve public URL gaps", "Check high-impact MW claims", "Confirm no private coordinates are exported"]; return { schema: "DataCenterLedger.RegionalEvidencePacket.v2.3", generatedAt: nowIso(), appVersion: APP_VERSION, region, records: regionRecords, sourceQuality: regionRecords.map((record) => reportMap.get(record.id) || scoreRecord(record)), checklist, digest: digest({ region, regionRecords, checklist }) }; }
function generateReviewTasks(records: LedgerRecord[], reports: SourceQualityReport[], overrides: Record<string, TaskStatus>, manualTasks: ReviewTask[]): ReviewTask[] { const reportMap = new Map(reports.map((report) => [report.recordId, report])); const generated: ReviewTask[] = []; records.forEach((record) => { const report = reportMap.get(record.id) || scoreRecord(record); const base = { recordId: record.id, regionId: `${record.state}::${record.county}`, createdAt: "generated", source: "generated" as const }; const add = (suffix: string, title: string, category: TaskCategory, priority: "low" | "medium" | "high", detail: string) => { const id = `task-${suffix}-${record.id}`; generated.push({ ...base, id, title, category, priority, detail, status: overrides[id] || "open" }); }; record.reviewWarnings.forEach((warning, index) => add(`warning-${index}`, `Resolve warning: ${warning}`, "needs_warning_resolution", "high", warning)); if (report.publicLinkCoverage < 80) add("public-url", "Add public source URL coverage", "needs_public_url", "high", "Attach public links to source receipts where available."); if (report.highImpactClaimCoverage === "needs_second_source") add("second-source", "Find second source for MW claim", "needs_second_source", "high", "MW/capacity claims require stronger corroboration before promotion."); if (report.score < 65) add("quality", "Improve source quality score", "needs_source_quality", "medium", report.gaps.join("; ")); if (record.precision === "unknown") add("location", "Review location precision", "needs_location_review", "medium", "Use state/county/city-level precision only unless exact location is already public."); if (canonicalBlockers(record, report).length === 0) add("promotion", "Ready for promotion review", "ready_for_promotion", "low", "Record currently passes canonical gate."); }); return [...manualTasks, ...generated]; }
function buildRecordBrief(record: LedgerRecord, report: SourceQualityReport): PublicBrief { const keyClaims = [`${record.name} is tracked as ${record.status} in ${record.county}, ${record.state}.`, `Current source quality: ${report.score} (${report.band}).`, `Lifecycle: ${record.lifecycle}.`]; const unresolvedGaps = Array.from(new Set([...record.reviewWarnings, ...report.gaps])); const relatedRecords = [{ id: record.id, name: record.name, state: record.state, county: record.county, canonicalBlockers: canonicalBlockers(record, report) }]; const payload = { schema: "DataCenterLedger.PublicBrief.v2.3", generatedAt: nowIso(), appVersion: APP_VERSION, scope: "record" as BriefScope, title: `Public Review Brief: ${record.name}`, summary: `Review-only summary for ${record.name}.`, reviewOnlyNotice, boundary: publicBoundary, keyClaims, sourceReceipts: record.receipts, unresolvedGaps, quality: report, relatedRecords, digest: "pending" }; return { ...payload, digest: digest(payload) }; }
function buildRegionBrief(region: RegionalSummary, records: LedgerRecord[], reports: SourceQualityReport[]): PublicBrief { const regionRecords = recordsForRegion(region, records); const reportMap = new Map(reports.map((report) => [report.recordId, report])); const sourceReceipts = regionRecords.flatMap((record) => record.receipts).slice(0, 12); const relatedRecords = regionRecords.map((record) => ({ id: record.id, name: record.name, state: record.state, county: record.county, canonicalBlockers: canonicalBlockers(record, reportMap.get(record.id) || scoreRecord(record)) })); const payload = { schema: "DataCenterLedger.PublicBrief.v2.3", generatedAt: nowIso(), appVersion: APP_VERSION, scope: "region" as BriefScope, title: `Map-Safe Regional Brief: ${region.label}`, summary: `${region.records} record(s), ${region.canonical} canonical, ${region.needsReview} needing review.`, reviewOnlyNotice, boundary: publicBoundary, keyClaims: [`${region.label} has ${region.records} review record(s).`, `Average source quality is ${region.averageQuality}.`], sourceReceipts, unresolvedGaps: region.reviewGaps, quality: { averageQuality: region.averageQuality, qualityBands: region.qualityBands, regionalRecords: region.records }, relatedRecords, digest: "pending" }; return { ...payload, digest: digest(payload) }; }
function briefToMarkdown(brief: PublicBrief) { return `# ${brief.title}\n\n${brief.reviewOnlyNotice}\n\n## Summary\n${brief.summary}\n\n## Public Boundary\n${brief.boundary.map((item) => `- ${item}`).join("\n")}\n\n## Key Claims\n${brief.keyClaims.map((item) => `- ${item}`).join("\n")}\n\n## Receipts\n${brief.sourceReceipts.map((receipt) => `- ${receipt.sourceName} (${receipt.sourceType}, ${receipt.confidence}): ${receipt.claim}${receipt.sourceUrl ? ` — ${receipt.sourceUrl}` : ""}`).join("\n")}\n\n## Unresolved Gaps\n${brief.unresolvedGaps.length ? brief.unresolvedGaps.map((item) => `- ${item}`).join("\n") : "None recorded."}\n\nDigest: ${brief.digest}\n`; }
function makeChangeDraft(record: LedgerRecord): RecordChangeDraft { return { name: record.name, operator: record.operator, status: record.status, lifecycle: record.lifecycle, state: record.state, county: record.county, city: record.city || "", precision: record.precision, capacityMW: record.capacityMW?.toString() || "", confidenceScore: record.confidenceScore.toString(), reviewWarnings: record.reviewWarnings.join("\n") }; }
function recordFromChangeDraft(record: LedgerRecord, draft: RecordChangeDraft): LedgerRecord { return { ...record, name: draft.name.trim() || record.name, operator: draft.operator.trim() || "Unknown", status: draft.status, lifecycle: draft.lifecycle, state: draft.state.trim() || record.state, county: draft.county.trim() || record.county, city: draft.city.trim() || undefined, precision: draft.precision, capacityMW: parseNumber(draft.capacityMW), confidenceScore: clampScore(draft.confidenceScore), reviewWarnings: draft.reviewWarnings.split(/\n/).map((item) => item.trim()).filter(Boolean) }; }
function buildChangeDeltas(before: LedgerRecord, draft: RecordChangeDraft): ChangeDelta[] { const beforeDraft = makeChangeDraft(before); return (Object.keys(beforeDraft) as Array<keyof RecordChangeDraft>).flatMap((field) => { const beforeValue = beforeDraft[field].toString(); const afterValue = draft[field].toString(); if (beforeValue === afterValue) return []; const highFields: Array<keyof RecordChangeDraft> = ["state", "county", "city", "precision", "capacityMW", "lifecycle"]; const mediumFields: Array<keyof RecordChangeDraft> = ["status", "confidenceScore", "reviewWarnings"]; const impact: ChangeDelta["impact"] = highFields.includes(field) ? "high" : mediumFields.includes(field) ? "medium" : "low"; return [{ field, before: beforeValue || "—", after: afterValue || "—", impact }]; }); }
function makeChangeReceiptFromApproval(request: ChangeApprovalRequest, reviewer: string, decisionNote: string): ChangeReceipt { const changedAt = nowIso(); const changeId = digest({ approvalId: request.approvalId, changedAt, reviewer, decisionNote }); return { changeId, recordId: request.recordId, recordName: request.recordName, changedAt, reviewer: reviewer.trim() || "Approval reviewer", reason: `${request.reason} | Approval note: ${decisionNote.trim() || "Approved without additional note."}`, deltas: request.deltas, beforeQuality: request.beforeQuality, afterQuality: request.afterQuality, canonicalBefore: request.canonicalBefore, canonicalAfter: request.canonicalAfter, digest: digest({ changeId, approvalId: request.approvalId, deltas: request.deltas, beforeQuality: request.beforeQuality, afterQuality: request.afterQuality }) }; }

function buildPromotionAuditTimeline(record: LedgerRecord, report: SourceQualityReport, importHistory: ImportHistoryItem[], receiptHistory: ReceiptEditHistoryItem[], tasks: ReviewTask[], promotionHistory: PromotionReceipt[], sessionHistory: SessionHistoryItem[], changeHistory: ChangeReceipt[], approvalQueue: ChangeApprovalRequest[], brief: PublicBrief): PromotionAuditTimeline { const events: AuditTimelineEvent[] = []; if (record.importBatchId) { const batch = importHistory.find((item) => item.batchId === record.importBatchId); events.push({ id: digest({ type: "import", record: record.id, batch }), type: "import", recordId: record.id, title: "Imported into workspace", occurredAt: batch?.committedAt || nowIso(), detail: `Batch ${record.importBatchId}`, status: batch ? "committed" : "batch reference", digest: digest({ record: record.id, batch }) }); } record.receipts.forEach((receipt, index) => events.push({ id: receipt.receiptId || digest({ receipt, index }), type: "receipt", recordId: record.id, title: `Receipt: ${receipt.sourceName}`, occurredAt: receipt.retrievedAt, detail: receipt.claim, status: receipt.confidence, digest: digest(receipt) })); receiptHistory.filter((item) => item.recordId === record.id).forEach((item) => events.push({ id: item.receiptId, type: "receipt", recordId: record.id, title: `Manual receipt added: ${item.sourceName}`, occurredAt: item.addedAt, detail: `${item.resolvedWarnings.length} warning(s) resolved.`, status: item.confidence, digest: item.digest })); tasks.filter((task) => task.recordId === record.id).forEach((task) => events.push({ id: task.id, type: "task", recordId: record.id, title: task.title, occurredAt: task.createdAt === "generated" ? nowIso() : task.createdAt, detail: task.detail, status: task.status, digest: digest(task) })); events.push({ id: brief.digest, type: "brief", recordId: record.id, title: "Public brief generated", occurredAt: brief.generatedAt, detail: brief.summary, status: brief.scope, digest: brief.digest }); events.push({ id: report.digest, type: "quality", recordId: record.id, title: "Source quality scored", occurredAt: nowIso(), detail: `${report.score} (${report.band})`, status: report.band, digest: report.digest }); if (record.lifecycle === "reviewed" || record.lifecycle === "promoted_public") events.push({ id: digest({ type: "reviewed", record }), type: "reviewed", recordId: record.id, title: "Record marked reviewed", occurredAt: nowIso(), detail: "Record has passed into reviewed/promoted workflow.", status: record.lifecycle, digest: digest({ record }) }); promotionHistory.filter((item) => item.recordId === record.id).forEach((item) => events.push({ id: item.promotionId, type: "promotion", recordId: record.id, title: "Promoted with receipt", occurredAt: item.promotedAt, actor: item.reviewer, detail: item.reason, status: "promoted_public", digest: item.digest })); changeHistory.filter((item) => item.recordId === record.id).forEach((item) => events.push({ id: item.changeId, type: "change", recordId: record.id, title: "Approved change applied", occurredAt: item.changedAt, actor: item.reviewer, detail: `${item.deltas.length} field delta(s). Reason: ${item.reason}`, status: item.canonicalAfter.length ? "review" : "clean", digest: item.digest })); approvalQueue.filter((item) => item.recordId === record.id).forEach((item) => events.push({ id: item.approvalId, type: "approval", recordId: record.id, title: `Change approval ${item.status}`, occurredAt: item.decidedAt || item.requestedAt, actor: item.decisionReviewer || item.requestedBy, detail: `${item.deltas.length} delta(s). ${item.decisionNote || item.reason}`, status: item.status, digest: item.digest })); sessionHistory.forEach((item) => events.push({ id: item.sessionId, type: "session_restore", recordId: record.id, title: "Session restored", occurredAt: item.restoredAt, detail: `${item.recordsRestored} record(s) restored from ${item.source}.`, status: item.sessionName, digest: item.digest })); record.notes.forEach((note, index) => events.push({ id: digest({ record: record.id, note, index }), type: "note", recordId: record.id, title: "Reviewer note", occurredAt: nowIso(), detail: note, digest: digest({ record: record.id, note, index }) })); const sortedEvents = events.sort((a, b) => new Date(b.occurredAt).getTime() - new Date(a.occurredAt).getTime()); const summary = { imports: sortedEvents.filter((e) => e.type === "import").length, receipts: sortedEvents.filter((e) => e.type === "receipt").length, tasks: sortedEvents.filter((e) => e.type === "task").length, briefs: sortedEvents.filter((e) => e.type === "brief").length, promotions: sortedEvents.filter((e) => e.type === "promotion").length, changes: sortedEvents.filter((e) => e.type === "change").length, approvals: sortedEvents.filter((e) => e.type === "approval").length, sessionRestores: sortedEvents.filter((e) => e.type === "session_restore").length, latestEvent: sortedEvents[0]?.occurredAt || null }; const payload = { schema: "DataCenterLedger.PromotionAuditTimeline.v2.3", generatedAt: nowIso(), appVersion: APP_VERSION, recordId: record.id, recordName: record.name, events: sortedEvents, summary, digest: "pending" }; return { ...payload, digest: digest(payload) }; }

function downloadJson(filename: string, payload: unknown) { downloadBlob(filename, new Blob([JSON.stringify(payload, null, 2)], { type: "application/json" })); }
function downloadText(filename: string, text: string) { downloadBlob(filename, new Blob([text], { type: "text/markdown" })); }
function downloadBlob(filename: string, blob: Blob) { const url = URL.createObjectURL(blob); const anchor = document.createElement("a"); anchor.href = url; anchor.download = filename; anchor.click(); URL.revokeObjectURL(url); }
function Stat({ label, value }: { label: string; value: number | string }) { return <div className="stat"><span>{label}</span><strong>{value}</strong></div>; }

export default function App() {
  const [records, setRecords] = useState<LedgerRecord[]>(starterRecords);
  const [selectedId, setSelectedId] = useState(starterRecords[0].id);
  const [query, setQuery] = useState("");
  const [stateFilter, setStateFilter] = useState("all");
  const [mode, setMode] = useState<"all" | "canonical" | "review">("all");
  const [importText, setImportText] = useState("");
  const [importPreview, setImportPreview] = useState<ImportPreview | null>(null);
  const [importHistory, setImportHistory] = useState<ImportHistoryItem[]>([]);
  const [receiptDraft, setReceiptDraft] = useState<ReceiptDraft>(() => makeEmptyReceiptDraft());
  const [receiptHistory, setReceiptHistory] = useState<ReceiptEditHistoryItem[]>([]);
  const [regionMode, setRegionMode] = useState<RegionMode>("state");
  const [selectedRegionId, setSelectedRegionId] = useState("");
  const [sessionName, setSessionName] = useState("Local review session");
  const [sessionText, setSessionText] = useState("");
  const [sessionHistory, setSessionHistory] = useState<SessionHistoryItem[]>([]);
  const [taskStatusOverrides, setTaskStatusOverrides] = useState<Record<string, TaskStatus>>({});
  const [manualTasks, setManualTasks] = useState<ReviewTask[]>([]);
  const [manualTaskText, setManualTaskText] = useState("");
  const [briefScope, setBriefScope] = useState<BriefScope>("record");
  const [promotionReviewer, setPromotionReviewer] = useState("Local reviewer");
  const [promotionReason, setPromotionReason] = useState("");
  const [promotionSafetyAck, setPromotionSafetyAck] = useState(false);
  const [promotionBriefAck, setPromotionBriefAck] = useState(false);
  const [promotionHistory, setPromotionHistory] = useState<PromotionReceipt[]>([]);
  const [changeDraft, setChangeDraft] = useState<RecordChangeDraft>(() => makeChangeDraft(starterRecords[0]));
  const [changeReason, setChangeReason] = useState("");
  const [changeReviewer, setChangeReviewer] = useState("Local reviewer");
  const [changeHistory, setChangeHistory] = useState<ChangeReceipt[]>([]);
  const [approvalQueue, setApprovalQueue] = useState<ChangeApprovalRequest[]>([]);
  const [approvalReviewer, setApprovalReviewer] = useState("Approval reviewer");
  const [approvalDecisionNote, setApprovalDecisionNote] = useState("");

  const selected = records.find((record) => record.id === selectedId) || records[0] || starterRecords[0];
  const reports = useMemo(() => records.map(scoreRecord), [records]);
  const reportMap = useMemo(() => new Map(reports.map((report) => [report.recordId, report])), [reports]);
  const selectedReport = reportMap.get(selected.id) || scoreRecord(selected);
  const states = useMemo(() => Array.from(new Set(records.map((record) => record.state))).sort(), [records]);
  const canonicalRecords = records.filter((record) => canonicalBlockers(record, reportMap.get(record.id) || scoreRecord(record)).length === 0);
  const reviewRecords = records.filter((record) => canonicalBlockers(record, reportMap.get(record.id) || scoreRecord(record)).length > 0);
  const regionalSummaries = useMemo(() => buildRegionalSummaries(records, reports, regionMode), [records, reports, regionMode]);
  const selectedRegion = regionalSummaries.find((region) => region.id === selectedRegionId) || regionalSummaries[0];
  const importWarnings = allPreviewWarnings(importPreview);
  const hasBlockingImport = importWarnings.some((warning) => warning.level === "blocking");
  const receiptDraftWarnings = validateReceiptDraft(receiptDraft);
  const hasBlockingReceiptDraft = receiptDraftWarnings.some((warning) => warning.level === "blocking");
  const selectedBrief = briefScope === "record" ? buildRecordBrief(selected, selectedReport) : selectedRegion ? buildRegionBrief(selectedRegion, records, reports) : buildRecordBrief(selected, selectedReport);
  const selectedRecordBrief = buildRecordBrief(selected, selectedReport);
  const selectedRegionPacket = selectedRegion ? buildRegionalEvidencePacket(selectedRegion, records, reports) : null;
  const tasks = generateReviewTasks(records, reports, taskStatusOverrides, manualTasks);
  const promotionChecklistItems = promotionChecklist(selected, selectedReport, promotionBriefAck, promotionSafetyAck, promotionReason);
  const canPromoteSelected = checklistPasses(promotionChecklistItems);
  const selectedAuditTimeline = buildPromotionAuditTimeline(selected, selectedReport, importHistory, receiptHistory, tasks, promotionHistory, sessionHistory, changeHistory, approvalQueue, selectedRecordBrief);
  const proposedRecord = recordFromChangeDraft(selected, changeDraft);
  const proposedReport = scoreRecord(proposedRecord);
  const changeDeltas = buildChangeDeltas(selected, changeDraft);
  const changeReasonReady = changeReason.trim().length >= 12;
  const pendingApprovals = approvalQueue.filter((item) => item.status === "pending");
  const hasPendingApprovalForSelected = pendingApprovals.some((item) => item.recordId === selected.id);
  const canSubmitApproval = changeDeltas.length > 0 && changeReasonReady && !hasPendingApprovalForSelected;
  const visibleRecords = records.filter((record) => { const haystack = `${record.name} ${record.operator} ${record.county} ${record.city || ""}`.toLowerCase(); const matchesQuery = haystack.includes(query.toLowerCase()); const matchesState = stateFilter === "all" || record.state === stateFilter; const blockers = canonicalBlockers(record, reportMap.get(record.id) || scoreRecord(record)); const matchesMode = mode === "all" || (mode === "canonical" ? blockers.length === 0 : blockers.length > 0); return matchesQuery && matchesState && matchesMode; });

  function selectRecord(recordId: string) { const record = records.find((item) => item.id === recordId); setSelectedId(recordId); if (record) setChangeDraft(makeChangeDraft(record)); }
  function previewImportFromText(origin = "pasted CSV") { setImportPreview(buildImportPreview(importText, origin, records)); }
  function loadSampleImport() { setImportText(sampleCsv); setImportPreview(buildImportPreview(sampleCsv, "sample CSV", records)); }
  async function loadCsvFile(file: File) { const text = await file.text(); setImportText(text); setImportPreview(buildImportPreview(text, file.name, records)); }
  function commitImportPreview() { if (!importPreview || hasBlockingImport) return; const importedRecords = importPreview.rows.map((row) => row.record); setRecords((items) => [...items, ...importedRecords]); setImportHistory((items) => [{ batchId: importPreview.batchId, committedAt: nowIso(), origin: importPreview.origin, rowsCommitted: importedRecords.length, warningCount: importWarnings.length, digest: importPreview.digest }, ...items]); if (importedRecords[0]) selectRecord(importedRecords[0].id); setImportPreview(null); setImportText(""); }
  function addReceiptToSelected() { if (hasBlockingReceiptDraft) return; const addedAt = nowIso(); const receipt = buildReceiptFromDraft(receiptDraft, selected, addedAt); const resolution = resolveWarningsAfterReceipt(selected, receipt); const historyItem: ReceiptEditHistoryItem = { receiptId: receipt.receiptId || digest({ receipt, addedAt }), recordId: selected.id, recordName: selected.name, addedAt, sourceName: receipt.sourceName, sourceType: receipt.sourceType, confidence: receipt.confidence, resolvedWarnings: resolution.resolved, remainingWarnings: resolution.remaining.length, digest: digest({ receipt, selected: selected.id, addedAt, resolution }) }; setRecords((items) => items.map((item) => item.id === selected.id ? { ...item, receipts: [...item.receipts, receipt], reviewWarnings: resolution.remaining, notes: [...item.notes, `Receipt ${historyItem.receiptId} added at ${new Date(addedAt).toLocaleString()} from ${receipt.sourceName}.`] } : item)); setReceiptHistory((items) => [historyItem, ...items]); setReceiptDraft(makeEmptyReceiptDraft()); }
  function markSelectedReviewed() { setRecords((items) => items.map((item) => item.id === selected.id ? { ...item, lifecycle: "reviewed", notes: [...item.notes, `Marked reviewed at ${new Date().toLocaleString()} before canonical promotion.`] } : item)); setChangeDraft((draft) => ({ ...draft, lifecycle: "reviewed" })); }
  function promoteSelectedWithReceipt() { if (!canPromoteSelected) return; const promotedAt = nowIso(); const promotionId = digest({ recordId: selected.id, promotedAt, promotionReviewer, promotionReason, promotionChecklistItems, selectedReport }); const receipt: PromotionReceipt = { promotionId, recordId: selected.id, recordName: selected.name, promotedAt, reviewer: promotionReviewer.trim() || "Local reviewer", reason: promotionReason.trim(), checklist: promotionChecklistItems, sourceQuality: selectedReport, publicBriefReady: promotionBriefAck, safetyAcknowledged: promotionSafetyAck, priorLifecycle: selected.lifecycle, digest: digest({ promotionId, selected, promotionChecklistItems, selectedReport }) }; setRecords((items) => items.map((item) => item.id === selected.id ? { ...item, lifecycle: "promoted_public", reviewWarnings: [], notes: [...item.notes, `Promoted through Canonical Review Mode at ${new Date(promotedAt).toLocaleString()}. Promotion receipt: ${promotionId}. Reason: ${promotionReason.trim()}`] } : item)); setPromotionHistory((items) => [receipt, ...items]); setTaskStatusOverrides((items) => ({ ...items, [`task-promotion-${selected.id}`]: "done" })); setPromotionReason(""); setPromotionSafetyAck(false); setPromotionBriefAck(false); setChangeDraft((draft) => ({ ...draft, lifecycle: "promoted_public", reviewWarnings: "" })); }
  function addManualTask() { if (!manualTaskText.trim()) return; const createdAt = nowIso(); const task: ReviewTask = { id: digest({ manualTaskText, selectedId, createdAt }), recordId: selected.id, regionId: `${selected.state}::${selected.county}`, title: manualTaskText.trim(), category: "manual_follow_up", status: "open", priority: "medium", detail: `Manual follow-up for ${selected.name}.`, createdAt, source: "manual" }; setManualTasks((items) => [task, ...items]); setManualTaskText(""); }
  function updateTaskStatus(taskId: string, status: TaskStatus) { setTaskStatusOverrides((items) => ({ ...items, [taskId]: status })); }
  function resetChangeDraft() { setChangeDraft(makeChangeDraft(selected)); setChangeReason(""); }
  function submitChangeForApproval() { if (!canSubmitApproval) return; const requestedAt = nowIso(); const approvalId = digest({ recordId: selected.id, requestedAt, changeReviewer, changeReason, changeDeltas }); const request: ChangeApprovalRequest = { approvalId, recordId: selected.id, recordName: selected.name, requestedAt, requestedBy: changeReviewer.trim() || "Change requester", reason: changeReason.trim(), status: "pending", deltas: changeDeltas, recordBefore: selected, recordAfter: proposedRecord, beforeQuality: selectedReport, afterQuality: proposedReport, canonicalBefore: canonicalBlockers(selected, selectedReport), canonicalAfter: canonicalBlockers(proposedRecord, proposedReport), digest: digest({ approvalId, selected, proposedRecord, changeDeltas, selectedReport, proposedReport }) }; setApprovalQueue((items) => [request, ...items]); setChangeReason(""); }
  function approveChangeRequest(request: ChangeApprovalRequest) { if (request.status !== "pending") return; const decidedAt = nowIso(); const receipt = makeChangeReceiptFromApproval(request, approvalReviewer, approvalDecisionNote); const note = approvalDecisionNote.trim() || "Approved for local workspace application."; setRecords((items) => items.map((item) => item.id === request.recordId ? { ...request.recordAfter, notes: [...request.recordAfter.notes, `Approved change applied at ${new Date(decidedAt).toLocaleString()}. Approval: ${request.approvalId}. Change receipt: ${receipt.changeId}. Note: ${note}`] } : item)); setChangeHistory((items) => [receipt, ...items]); setApprovalQueue((items) => items.map((item) => item.approvalId === request.approvalId ? { ...item, status: "approved", decidedAt, decisionReviewer: approvalReviewer.trim() || "Approval reviewer", decisionNote: note, appliedChangeId: receipt.changeId, digest: digest({ ...item, status: "approved", decidedAt, note, appliedChangeId: receipt.changeId }) } : item)); setApprovalDecisionNote(""); if (selected.id === request.recordId) setChangeDraft(makeChangeDraft(request.recordAfter)); }
  function rejectChangeRequest(request: ChangeApprovalRequest) { if (request.status !== "pending") return; const decidedAt = nowIso(); const note = approvalDecisionNote.trim() || "Rejected for more review before applying."; setApprovalQueue((items) => items.map((item) => item.approvalId === request.approvalId ? { ...item, status: "rejected", decidedAt, decisionReviewer: approvalReviewer.trim() || "Approval reviewer", decisionNote: note, digest: digest({ ...item, status: "rejected", decidedAt, note }) } : item)); setApprovalDecisionNote(""); }

  function exportLedger() { downloadJson("datacenter-ledger-export.json", { schema: "DataCenterLedger.Export.v2.3-change-approval-queue", generatedAt: nowIso(), appVersion: APP_VERSION, boundary: publicBoundary, records, importHistory, receiptHistory, promotionHistory, changeHistory, approvalQueue, sessionHistory, sourceQuality: reports, regionalSummaries, tasks, selectedAuditTimeline, digest: digest({ records, importHistory, receiptHistory, promotionHistory, changeHistory, approvalQueue, sessionHistory, reports, tasks, selectedAuditTimeline }) }); }
  function exportCanonical() { const included = canonicalRecords; const excluded = records.filter((record) => canonicalBlockers(record, reportMap.get(record.id) || scoreRecord(record)).length > 0).map((record) => ({ id: record.id, name: record.name, blockers: canonicalBlockers(record, reportMap.get(record.id) || scoreRecord(record)) })); downloadJson("datacenter-ledger-canonical.json", { schema: "DataCenterLedger.CanonicalRegistry.v2.3-change-approval", generatedAt: nowIso(), appVersion: APP_VERSION, promotionHistory, changeHistory, approvalQueue, included, excluded, digest: digest({ included, excluded, promotionHistory, changeHistory, approvalQueue }) }); }
  function exportChangeHistory() { downloadJson("datacenter-ledger-change-history.json", { schema: "DataCenterLedger.ChangeHistory.v2.3", generatedAt: nowIso(), appVersion: APP_VERSION, changeHistory, approvalQueue, digest: digest({ changeHistory, approvalQueue }) }); }
  function exportApprovalQueue() { downloadJson("datacenter-ledger-change-approval-queue.json", { schema: "DataCenterLedger.ChangeApprovalQueue.v2.3", generatedAt: nowIso(), appVersion: APP_VERSION, approvalQueue, pending: pendingApprovals.length, digest: digest(approvalQueue) }); }
  function exportSelectedChangePacket() { downloadJson("datacenter-ledger-selected-change-approval-request.json", { schema: "DataCenterLedger.PendingChangeReview.v2.3", generatedAt: nowIso(), appVersion: APP_VERSION, recordBefore: selected, recordAfter: proposedRecord, deltas: changeDeltas, beforeQuality: selectedReport, afterQuality: proposedReport, canonicalBefore: canonicalBlockers(selected, selectedReport), canonicalAfter: canonicalBlockers(proposedRecord, proposedReport), reason: changeReason, readyForApprovalQueue: canSubmitApproval, existingPendingApproval: hasPendingApprovalForSelected, digest: digest({ selected, proposedRecord, changeDeltas, selectedReport, proposedReport, changeReason }) }); }
  function exportSelectedAuditTimeline() { downloadJson("datacenter-ledger-promotion-audit-timeline.json", selectedAuditTimeline); }
  function exportRegionalPacket() { if (selectedRegionPacket) downloadJson("datacenter-ledger-regional-evidence-packet.json", selectedRegionPacket); }
  function exportReviewQueue() { downloadJson("datacenter-ledger-review-queue.json", { schema: "DataCenterLedger.ReviewQueue.v2.3", generatedAt: nowIso(), appVersion: APP_VERSION, tasks, taskStatusOverrides, manualTasks, digest: digest({ tasks, taskStatusOverrides, manualTasks }) }); }
  function exportPublicBriefJson() { downloadJson("datacenter-ledger-public-brief.json", selectedBrief); }
  function exportPublicBriefMarkdown() { downloadText("datacenter-ledger-public-brief.md", briefToMarkdown(selectedBrief)); }
  function buildSession(): LocalReviewSession { const session: LocalReviewSession = { schema: "DataCenterLedger.LocalReviewSession.v2.3", generatedAt: nowIso(), appVersion: APP_VERSION, sessionName, records, importHistory, receiptHistory, promotionHistory, changeHistory, approvalQueue, sessionHistory, taskStatusOverrides, manualTasks, uiState: { selectedId, query, stateFilter, mode, regionMode, selectedRegionId: selectedRegion?.id || "", briefScope }, digest: "pending" }; return { ...session, digest: digest(session) }; }
  function exportSession() { downloadJson("datacenter-ledger-local-review-session.json", buildSession()); }
  function restoreSessionFromText(text: string) { const parsed = JSON.parse(text) as LocalReviewSession; if (!parsed.schema?.startsWith("DataCenterLedger.LocalReviewSession")) throw new Error("Invalid DataCenterLedger session schema."); const restoredAt = nowIso(); const restoredRecordCount = parsed.records?.length || 0; const restoreEvent: SessionHistoryItem = { sessionId: digest({ schema: parsed.schema, restoredAt, sessionName: parsed.sessionName, records: restoredRecordCount }), sessionName: parsed.sessionName || "Restored session", restoredAt, source: "local_json_restore", recordsRestored: restoredRecordCount, digest: digest({ restoredAt, restoredRecordCount }) }; setSessionName(parsed.sessionName || "Restored session"); setRecords(parsed.records || starterRecords); setImportHistory(parsed.importHistory || []); setReceiptHistory(parsed.receiptHistory || []); setPromotionHistory(parsed.promotionHistory || []); setChangeHistory(parsed.changeHistory || []); setApprovalQueue(parsed.approvalQueue || []); setSessionHistory([restoreEvent, ...(parsed.sessionHistory || [])]); setTaskStatusOverrides(parsed.taskStatusOverrides || {}); setManualTasks(parsed.manualTasks || []); setSelectedId(parsed.uiState?.selectedId || parsed.records?.[0]?.id || starterRecords[0].id); setQuery(parsed.uiState?.query || ""); setStateFilter(parsed.uiState?.stateFilter || "all"); setMode(parsed.uiState?.mode || "all"); setRegionMode(parsed.uiState?.regionMode || "state"); setSelectedRegionId(parsed.uiState?.selectedRegionId || ""); setBriefScope(parsed.uiState?.briefScope || "record"); setChangeDraft(makeChangeDraft((parsed.records || starterRecords).find((record) => record.id === parsed.uiState?.selectedId) || (parsed.records || starterRecords)[0])); }
  function resetDemoData() { setRecords(starterRecords); setSelectedId(starterRecords[0].id); setImportHistory([]); setReceiptHistory([]); setPromotionHistory([]); setChangeHistory([]); setApprovalQueue([]); setSessionHistory([]); setTaskStatusOverrides({}); setManualTasks([]); setQuery(""); setStateFilter("all"); setMode("all"); setChangeDraft(makeChangeDraft(starterRecords[0])); }

  return (
    <main className="shell">
      <header className="hero launchHero"><div><p className="eyebrow">v{APP_VERSION} change approval queue • local-first • public-safe</p><h1>DataCenterLedger Explorer</h1><p>A civic transparency workbench for reviewing public data center records as claims — with receipts, quality scoring, regional packets, public briefs, tasks, sessions, promotion receipts, audit timelines, canonical diff review, and approval-gated changes.</p><div className="boundaryPills">{publicBoundary.map((item) => <span key={item}>{item}</span>)}</div></div><div className="heroActions"><button onClick={exportLedger}>Export Ledger</button><button onClick={exportCanonical}>Export Canonical</button><button onClick={exportSession}>Export Session</button></div></header>
      <section className="cards"><Stat label="Records" value={records.length} /><Stat label="Canonical" value={canonicalRecords.length} /><Stat label="Needs review" value={reviewRecords.length} /><Stat label="Receipts" value={records.reduce((sum, record) => sum + record.receipts.length, 0)} /><Stat label="Pending approvals" value={pendingApprovals.length} /><Stat label="Changes" value={changeHistory.length} /><Stat label="Audit events" value={selectedAuditTimeline.events.length} /><Stat label="Tasks" value={tasks.length} /></section>
      <section className="panel changeApprovalPanel"><div className="panelHeader"><div><p className="eyebrow">v2.3 Change Approval Queue</p><h2>Submit proposed changes for approval before they touch the workspace</h2><p className="muted">Selected record: <strong>{selected.name}</strong>. The queue stores before/after fields, deltas, quality snapshots, canonical blockers, requester reason, and approval decision notes.</p></div><div className="heroActions"><button onClick={exportSelectedChangePacket}>Export Pending Change Packet</button><button onClick={exportApprovalQueue}>Export Approval Queue</button><button onClick={exportChangeHistory} disabled={changeHistory.length === 0 && approvalQueue.length === 0}>Export Change History</button></div></div><div className="approvalStats"><Stat label="Pending" value={pendingApprovals.length} /><Stat label="Approved" value={approvalQueue.filter((item) => item.status === "approved").length} /><Stat label="Rejected" value={approvalQueue.filter((item) => item.status === "rejected").length} /><Stat label="Selected pending" value={hasPendingApprovalForSelected ? "yes" : "no"} /></div><div className="changeGrid"><div className="changeForm"><label>Name<input value={changeDraft.name} onChange={(event) => setChangeDraft((draft) => ({ ...draft, name: event.target.value }))} /></label><label>Operator<input value={changeDraft.operator} onChange={(event) => setChangeDraft((draft) => ({ ...draft, operator: event.target.value }))} /></label><label>Status<select value={changeDraft.status} onChange={(event) => setChangeDraft((draft) => ({ ...draft, status: event.target.value as Status }))}>{validStatuses.map((status) => <option key={status} value={status}>{status}</option>)}</select></label><label>Lifecycle<select value={changeDraft.lifecycle} onChange={(event) => setChangeDraft((draft) => ({ ...draft, lifecycle: event.target.value as Lifecycle }))}>{["raw_import", "local_working", "reviewed", "promoted_public", "rejected_duplicate", "retired"].map((lifecycle) => <option key={lifecycle} value={lifecycle}>{lifecycle}</option>)}</select></label><label>State<input value={changeDraft.state} onChange={(event) => setChangeDraft((draft) => ({ ...draft, state: event.target.value }))} /></label><label>County<input value={changeDraft.county} onChange={(event) => setChangeDraft((draft) => ({ ...draft, county: event.target.value }))} /></label><label>City<input value={changeDraft.city} onChange={(event) => setChangeDraft((draft) => ({ ...draft, city: event.target.value }))} /></label><label>Precision<select value={changeDraft.precision} onChange={(event) => setChangeDraft((draft) => ({ ...draft, precision: event.target.value as Precision }))}>{validPrecisions.map((precision) => <option key={precision} value={precision}>{precision}</option>)}</select></label><label>MW<input value={changeDraft.capacityMW} onChange={(event) => setChangeDraft((draft) => ({ ...draft, capacityMW: event.target.value }))} /></label><label>Confidence<input value={changeDraft.confidenceScore} onChange={(event) => setChangeDraft((draft) => ({ ...draft, confidenceScore: event.target.value }))} /></label><label>Warnings<textarea value={changeDraft.reviewWarnings} onChange={(event) => setChangeDraft((draft) => ({ ...draft, reviewWarnings: event.target.value }))} /></label><label>Requester<input value={changeReviewer} onChange={(event) => setChangeReviewer(event.target.value)} /></label><label className="fullSpan">Change reason<textarea value={changeReason} onChange={(event) => setChangeReason(event.target.value)} placeholder="Required before entering approval queue..." /></label><div className="importActions fullSpan"><button onClick={submitChangeForApproval} disabled={!canSubmitApproval}>Submit Change for Approval</button><button onClick={resetChangeDraft}>Reset Draft</button></div>{hasPendingApprovalForSelected && <p className="dangerText fullSpan">This selected record already has a pending approval request. Resolve that request before submitting another.</p>}</div><div className="diffPanel"><div className="qualityDelta"><Stat label="Before quality" value={`${selectedReport.score} ${selectedReport.band}`} /><Stat label="After quality" value={`${proposedReport.score} ${proposedReport.band}`} /><Stat label="Deltas" value={changeDeltas.length} /><Stat label="Reason" value={changeReasonReady ? "ready" : "needed"} /></div><table><thead><tr><th>Field</th><th>Before</th><th>After</th><th>Impact</th></tr></thead><tbody>{changeDeltas.length ? changeDeltas.map((delta) => <tr key={delta.field}><td>{delta.field}</td><td>{delta.before}</td><td>{delta.after}</td><td><span className={`chip ${delta.impact === "high" ? "danger" : delta.impact === "medium" ? "warn" : "info"}`}>{delta.impact}</span></td></tr>) : <tr><td colSpan={4}>No field deltas yet.</td></tr>}</tbody></table><h3>Canonical impact after proposed change</h3>{canonicalBlockers(proposedRecord, proposedReport).length ? <ul>{canonicalBlockers(proposedRecord, proposedReport).map((blocker) => <li key={blocker}>{blocker}</li>)}</ul> : <p className="okText">Proposed record would pass the current canonical gate.</p>}</div></div><div className="approvalQueue"><div className="panelHeader"><div><h3>Approval requests</h3><p className="muted">Approving applies the change and creates a change receipt. Rejecting records the decision without changing the record.</p></div><label>Approval reviewer<input value={approvalReviewer} onChange={(event) => setApprovalReviewer(event.target.value)} /></label></div><label>Decision note<textarea value={approvalDecisionNote} onChange={(event) => setApprovalDecisionNote(event.target.value)} placeholder="Approval or rejection note..." /></label><div className="approvalList">{approvalQueue.length ? approvalQueue.map((request) => <article key={request.approvalId} className={`approvalCard ${request.status}`}><div><span className={`chip ${request.status === "pending" ? "warn" : request.status === "approved" ? "ok" : "danger"}`}>{request.status}</span><h4>{request.recordName}</h4><p>{request.reason}</p><small>{request.deltas.length} delta(s) • requested by {request.requestedBy} • {new Date(request.requestedAt).toLocaleString()}</small>{request.decisionNote && <p className="muted">Decision: {request.decisionNote}</p>}</div><div className="approvalActions"><button onClick={() => selectRecord(request.recordId)}>Open Record</button><button onClick={() => approveChangeRequest(request)} disabled={request.status !== "pending"}>Approve + Apply</button><button onClick={() => rejectChangeRequest(request)} disabled={request.status !== "pending"}>Reject</button></div></article>) : <p className="muted">No approval requests yet.</p>}</div></div></section>
      <section className="panel"><div className="panelHeader"><div><p className="eyebrow">v2.1 Promotion Audit Timeline</p><h2>{selectedAuditTimeline.recordName}</h2></div><button onClick={exportSelectedAuditTimeline}>Export Timeline</button></div><div className="timelineStats"><Stat label="Events" value={selectedAuditTimeline.events.length} /><Stat label="Approvals" value={selectedAuditTimeline.summary.approvals} /><Stat label="Changes" value={selectedAuditTimeline.summary.changes} /><Stat label="Receipts" value={selectedAuditTimeline.summary.receipts} /></div><div className="timelineList">{selectedAuditTimeline.events.slice(0, 8).map((event) => <article key={event.id} className="timelineCard"><span className="chip info">{event.type}</span><h4>{event.title}</h4><p>{event.detail}</p><small>{new Date(event.occurredAt).toLocaleString()} • {event.digest}</small></article>)}</div></section>
      <section className="panel"><div className="panelHeader"><div><p className="eyebrow">v2.0 Canonical Review Mode</p><h2>Promotion cockpit</h2></div><button onClick={markSelectedReviewed}>Mark reviewed</button></div><div className="checklistGrid">{promotionChecklistItems.map((item) => <article key={item.id} className="checkCard"><span className={`chip ${item.status === "pass" ? "ok" : item.status === "fail" ? "danger" : "warn"}`}>{item.status}</span><h4>{item.label}</h4><p>{item.detail}</p></article>)}</div><div className="changeForm"><label>Reviewer<input value={promotionReviewer} onChange={(event) => setPromotionReviewer(event.target.value)} /></label><label className="fullSpan">Promotion reason<textarea value={promotionReason} onChange={(event) => setPromotionReason(event.target.value)} /></label><label><input type="checkbox" checked={promotionBriefAck} onChange={(event) => setPromotionBriefAck(event.target.checked)} /> Public brief reviewed</label><label><input type="checkbox" checked={promotionSafetyAck} onChange={(event) => setPromotionSafetyAck(event.target.checked)} /> Public safety boundary acknowledged</label><button onClick={promoteSelectedWithReceipt} disabled={!canPromoteSelected}>Promote with Receipt</button></div></section>
      <section className="panel"><div className="panelHeader"><div><p className="eyebrow">v1.9 Public Brief Generator</p><h2>{selectedBrief.title}</h2></div><div className="heroActions"><select value={briefScope} onChange={(event) => setBriefScope(event.target.value as BriefScope)}><option value="record">Selected record</option><option value="region">Selected region</option></select><button onClick={exportPublicBriefJson}>Export JSON</button><button onClick={exportPublicBriefMarkdown}>Export Markdown</button></div></div><p className="muted">{selectedBrief.summary}</p><p>{reviewOnlyNotice}</p></section>
      <section className="panel"><div className="panelHeader"><div><p className="eyebrow">v1.8 Review Queue + Task Board</p><h2>Generated and manual tasks</h2></div><button onClick={exportReviewQueue}>Export Review Queue</button></div><div className="importActions"><input value={manualTaskText} onChange={(event) => setManualTaskText(event.target.value)} placeholder="Add manual task for selected record..." /><button onClick={addManualTask}>Add Task</button></div><div className="taskList">{tasks.slice(0, 10).map((task) => <article key={task.id} className="taskCard"><span className={`chip ${task.priority === "high" ? "danger" : task.priority === "medium" ? "warn" : "info"}`}>{task.priority}</span><h4>{task.title}</h4><p>{task.detail}</p><select value={task.status} onChange={(event) => updateTaskStatus(task.id, event.target.value as TaskStatus)}>{["open", "in_progress", "blocked", "done", "dismissed"].map((status) => <option key={status} value={status}>{status}</option>)}</select><button onClick={() => selectRecord(task.recordId)}>Open record</button></article>)}</div></section>
      <section className="panel"><div className="panelHeader"><div><p className="eyebrow">v1.7 Local Review Session</p><h2>Save / load workspace</h2></div><button onClick={exportSession}>Export Session</button></div><div className="changeForm"><label>Session name<input value={sessionName} onChange={(event) => setSessionName(event.target.value)} /></label><label className="fullSpan">Paste session JSON<textarea value={sessionText} onChange={(event) => setSessionText(event.target.value)} /></label><button onClick={() => restoreSessionFromText(sessionText)} disabled={!sessionText.trim()}>Restore Pasted Session</button><label className="fileButton">Load Session File<input type="file" accept=".json" onChange={async (event) => { const file = event.target.files?.[0]; if (file) restoreSessionFromText(await file.text()); event.currentTarget.value = ""; }} /></label></div></section>
      <section className="panel"><div className="panelHeader"><div><p className="eyebrow">v1.6 Regional Evidence Packet</p><h2>Map-safe regional view</h2></div><div className="heroActions"><select value={regionMode} onChange={(event) => { setRegionMode(event.target.value as RegionMode); setSelectedRegionId(""); }}><option value="state">State</option><option value="county">County</option></select><button onClick={exportRegionalPacket} disabled={!selectedRegionPacket}>Export Regional Packet</button></div></div><div className="regionalTable tableWrap"><table><thead><tr><th>Region</th><th>Records</th><th>Canonical</th><th>Needs review</th><th>Avg quality</th></tr></thead><tbody>{regionalSummaries.map((region) => <tr key={region.id} onClick={() => setSelectedRegionId(region.id)} className={selectedRegion?.id === region.id ? "selected" : ""}><td>{region.label}</td><td>{region.records}</td><td>{region.canonical}</td><td>{region.needsReview}</td><td>{region.averageQuality}</td></tr>)}</tbody></table></div></section>
      <section className="panel importWorkbench"><div className="panelHeader"><div><p className="eyebrow">v1.2 Import Workbench</p><h2>Preview CSV before commit</h2></div><div className="heroActions"><button onClick={loadSampleImport}>Load Sample CSV</button><label className="fileButton">Load CSV<input type="file" accept=".csv" onChange={(event) => { const file = event.target.files?.[0]; if (file) void loadCsvFile(file); event.currentTarget.value = ""; }} /></label></div></div><textarea className="csvTextArea" value={importText} onChange={(event) => setImportText(event.target.value)} /><div className="importActions"><button onClick={() => previewImportFromText()} disabled={!importText.trim()}>Preview CSV</button><button onClick={commitImportPreview} disabled={!importPreview || hasBlockingImport}>Commit Preview</button></div>{importPreview && <div className="previewPanel"><div className="previewSummary"><Stat label="Rows" value={importPreview.rows.length} /><Stat label="Warnings" value={importWarnings.length} /><Stat label="Blocking" value={importWarnings.filter((warning) => warning.level === "blocking").length} /><Stat label="Digest" value={importPreview.digest.slice(0, 10)} /></div></div>}</section>
      <section className="grid"><div className="panel"><div className="panelHeader"><div><p className="eyebrow">Working registry</p><h2>Review queue</h2></div><span className="countBadge">{visibleRecords.length} visible</span></div><section className="toolbar"><input value={query} onChange={(event) => setQuery(event.target.value)} placeholder="Search records..." /><select value={stateFilter} onChange={(event) => setStateFilter(event.target.value)}><option value="all">All states</option>{states.map((state) => <option key={state} value={state}>{state}</option>)}</select><select value={mode} onChange={(event) => setMode(event.target.value as typeof mode)}><option value="all">All records</option><option value="canonical">Canonical</option><option value="review">Needs review</option></select><button onClick={resetDemoData}>Reset Demo</button></section><div className="tableWrap"><table><thead><tr><th>Name</th><th>State</th><th>Status</th><th>Lifecycle</th><th>Quality</th><th>Gate</th></tr></thead><tbody>{visibleRecords.map((record) => { const report = reportMap.get(record.id) || scoreRecord(record); const blockers = canonicalBlockers(record, report); return <tr key={record.id} onClick={() => selectRecord(record.id)} className={record.id === selected.id ? "selected" : ""}><td><strong>{record.name}</strong><small>{record.operator}</small></td><td>{record.state}</td><td>{record.status}</td><td>{record.lifecycle}</td><td>{report.score} / {report.band}</td><td><span className={blockers.length ? "chip warn" : "chip ok"}>{blockers.length ? "review" : "canonical"}</span></td></tr>; })}</tbody></table></div></div><aside className="panel drawer"><p className="eyebrow">Selected record</p><h2>{selected.name}</h2><p className="muted">{selected.city ? `${selected.city}, ` : ""}{selected.county}, {selected.state} • {selected.precision}</p><div className="miniGrid"><Stat label="Quality" value={`${selectedReport.score} ${selectedReport.band}`} /><Stat label="Receipts" value={selected.receipts.length} /><Stat label="Warnings" value={selected.reviewWarnings.length} /></div><h3>Canonical blockers</h3>{canonicalBlockers(selected, selectedReport).length ? <ul>{canonicalBlockers(selected, selectedReport).map((blocker) => <li key={blocker}>{blocker}</li>)}</ul> : <p className="okText">Record passes canonical gate.</p>}<h3>Receipt editor</h3><div className="noteBox"><input value={receiptDraft.sourceName} onChange={(event) => setReceiptDraft((draft) => ({ ...draft, sourceName: event.target.value }))} placeholder="Source name" /><input value={receiptDraft.sourceUrl} onChange={(event) => setReceiptDraft((draft) => ({ ...draft, sourceUrl: event.target.value }))} placeholder="Public URL" /><select value={receiptDraft.sourceType} onChange={(event) => setReceiptDraft((draft) => ({ ...draft, sourceType: event.target.value as SourceType }))}>{validSourceTypes.map((sourceType) => <option key={sourceType} value={sourceType}>{sourceType}</option>)}</select><textarea value={receiptDraft.claim} onChange={(event) => setReceiptDraft((draft) => ({ ...draft, claim: event.target.value }))} placeholder="Claim supported..." /><button onClick={addReceiptToSelected} disabled={hasBlockingReceiptDraft}>Add Receipt</button></div>{receiptDraftWarnings.map((warning) => <span key={warning.message} className={`chip ${warning.level === "blocking" ? "danger" : "warn"}`}>{warning.message}</span>)}<h3>Receipts</h3>{selected.receipts.map((receipt, index) => <div key={receipt.receiptId || `${receipt.sourceName}-${index}`} className="receipt"><strong>{receipt.sourceName}</strong><span>{receipt.sourceType} • {receipt.confidence}</span><p>{receipt.claim}</p>{receipt.sourceUrl && <a href={receipt.sourceUrl} target="_blank" rel="noreferrer">Open public source</a>}</div>)}</aside></section>
    </main>
  );
}
